<!-- wp:proposal-crafter/paragraph {"uniqueId":"bc60897","css":".pcbc60897{border-style:none;border-color:#000000;border-width:0px 0px 0px 0px;margin:0px 0px 0px 0px !important;}.pcbc60897__overlay{padding:0px 0px 0px 0px !important;}.pcbc60897 .pc-paragraph{text-align:left;color:#000000;font-size:14px;font-family:Readex Pro;font-weight:300;}@media screen and (max-width: 767px){.pcbc60897 .pc-paragraph{font-size:14px;}}","content":"By signing this proposal you agree with the deliverables and terms of services. These terms are valid for only the said provision, and the remaining provisions (if there are any other) shall continue to be valid and enforceable.  ","fontSizeMobile":14,"fontWeight":"300","fontFamily":"Readex Pro"} -->
<div class="wp-block-proposal-crafter-paragraph pcbc60897" data-block-id="bc60897"><div class="pcbc60897__overlay"><p class="pc-paragraph">By signing this proposal you agree with the deliverables and terms of services. These terms are valid for only the said provision, and the remaining provisions (if there are any other) shall continue to be valid and enforceable.  </p></div></div>
